        safeDateFormat(date, { dateFormat, locale });
      return formatMultipleDates(selectedDates ?? [], formatDateFn);
    }
    return safeMultipleDatesFormat(selectedDates ?? [], {
      dateFormat,
      locale,
    });
  }
  return safeDateFormat(selected, {
    dateFormat,
    locale,
  });
